INSERT INTO "faqs" ("id", "question", "answer", "tags", "metadata", "status", "source", "source_row", "created_at", "updated_at") VALUES
('65c93f8a-2897-47ad-b703-71c9ac2f2005',	'Bệnh nhân có thể đặt lịch khám Tự nguyện 1 qua những kênh nào?',	'Bệnh nhân đặt lịch khám qua điện thoại, Website hoặc Fanpage của bệnh viện; thông tin đặt lịch cũng được ghi trên giấy hẹn khám lại và bìa hồ sơ khám để bệnh nhân tiếp cận.',	'{"đặt lịch khám","điện thoại","Website","Fanpage","giấy hẹn khám lại","bìa hồ sơ"}',	'{"topic": "Bước 1 - Nhận đặt lịch", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	1,	now(),	now()),
('12fb3e6a-6351-48dc-970a-b692f0db445b',	'Ai là người tiếp nhận đặt lịch khám và tư vấn quy trình khám cho bệnh nhân?',	'Nhân viên tổ chăm sóc khách hàng thuộc phòng Công tác xã hội là người nhận đặt lịch khám Tự nguyện 1 và tư vấn quy trình khám cho bệnh nhân.',	'{"chăm sóc khách hàng","phòng Công tác xã hội","tư vấn quy trình khám"}',	'{"topic": "Bước 1 - Nhận đặt lịch", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	2,	now(),	now()),
('b78796b3-efc4-4cfd-83f9-d8cf87803970',	'Sau khi đặt lịch thành công, bệnh nhân được thông báo những thông tin gì?',	'Bệnh nhân đặt lịch được nhân viên tư vấn thông báo mã đặt lịch (số thứ tự tự tiếp nhận), ngày khám và bác sĩ khám (nếu có).',	'{"mã đặt lịch","số thứ tự tự tiếp nhận","ngày khám","bác sĩ khám"}',	'{"topic": "Bước 1 - Nhận đặt lịch", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	3,	now(),	now()),
('814a0c29-585b-4434-9a97-3d2f26da0d4c',	'Bệnh nhân không đặt lịch trước thì lấy số khám bằng cách nào?',	'Bệnh nhân không đặt lịch trước đến lấy số trực tiếp tại cây lấy số tự động ở khu Tự nguyện 1.',	'{"không đặt lịch","lấy số trực tiếp","cây lấy số tự động"}',	'{"topic": "Bước 1 - Nhận đặt lịch", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	4,	now(),	now()),
('2df8e4f0-4e68-4c9a-9e65-2348e4d5d9d2',	'Bệnh nhân đã đặt lịch trước cần làm gì khi đến quầy tiếp nhận?',	'Bệnh nhân đã đặt lịch khi đến khám vào thẳng quầy tư vấn dành cho người đặt lịch trước và thông báo thông tin đã đặt lịch cho nhân viên tư vấn để làm thủ tục đăng ký khám.',	'{"đặt lịch trước","quầy tư vấn","thông tin đặt lịch","đăng ký khám"}',	'{"topic": "Bước 2 - Lấy số tiếp nhận", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	5,	now(),	now()),
('68ebaeec-9dd3-4a61-9634-ad0db5378134',	'Bệnh nhân không đặt lịch trước phải làm gì tại bước lấy số?',	'Bệnh nhân không đặt lịch trước đến lấy số thứ tự tại cây lấy số tự động và ngồi chờ gọi theo số thứ tự đã lấy.',	'{"không đặt lịch trước","cây lấy số tự động","số thứ tự","ngồi chờ"}',	'{"topic": "Bước 2 - Lấy số tiếp nhận", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	6,	now(),	now()),
('d85e5edf-d887-4e22-b55d-17c184517951',	'Hướng dẫn viên (HDV) có vai trò gì trong bước lấy số tiếp nhận?',	'HDV hướng dẫn bệnh nhân khu vực lấy số và ổn định trật tự khu vực chờ tiếp nhận.',	'{"HDV","hướng dẫn viên","khu vực lấy số","ổn định trật tự","khu vực chờ"}',	'{"topic": "Bước 2 - Lấy số tiếp nhận", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	7,	now(),	now()),
('0587a5c1-194f-48a0-b4d1-e79c88f6097a',	'Bệnh nhân đăng ký khám bệnh Tự nguyện 1 gồm những đối tượng nào?',	'Bệnh nhân đăng ký khám Tự nguyện 1 gồm: bệnh nhân có BHYT và không có BHYT; bệnh nhân tái khám và bệnh nhân khám mới.',	'{"đối tượng bệnh nhân","BHYT","tái khám","khám mới"}',	'{"topic": "Bước 3 - Tiếp nhận đăng ký khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	8,	now(),	now()),
('cbe02ec2-ba1f-4d1e-9af7-4032038ab2a4',	'Bệnh nhân khám lần đầu cần thực hiện thủ tục gì khi đăng ký?',	'Bệnh nhân khám lần đầu khai thông tin vào phiếu đăng ký khám bệnh.',	'{"khám lần đầu","phiếu đăng ký khám bệnh"}',	'{"topic": "Bước 3 - Tiếp nhận đăng ký khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	9,	now(),	now()),
('7194fcc5-54f4-4a05-be0f-71c6f324ed25',	'Bệnh nhân khám BHYT cần xuất trình những giấy tờ gì?',	'Bệnh nhân khám BHYT cần xuất trình giấy chuyển viện, giấy hẹn khám lại, thẻ BHYT, CCCD hoặc giấy tờ tùy thân có ảnh, và phô tô các giấy tờ cần thiết.',	'{"khám BHYT","giấy chuyển viện","giấy hẹn khám lại","thẻ BHYT","CCCD","phô tô giấy tờ"}',	'{"topic": "Bước 3 - Tiếp nhận đăng ký khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	10,	now(),	now()),
('a68e256a-8349-42d1-bc0d-c48af706f944',	'Nếu bệnh nhân không mang thẻ BHYT giấy khi đến khám thì dùng giấy tờ gì thay thế?',	'Trường hợp không mang thẻ BHYT giấy, bệnh nhân có thể dùng hình ảnh BHYT trên ứng dụng VssID hoặc CCCD gắn chíp có tích hợp thẻ BHYT để thay thế.',	'{"không mang thẻ BHYT","VssID","CCCD gắn chíp","thẻ BHYT thay thế"}',	'{"topic": "Bước 3 - Tiếp nhận đăng ký khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	11,	now(),	now()),
('9231198c-01ae-4575-b3ef-1912dc08dfb3',	'Khi nào bệnh nhân phải ký cam kết chi trả chênh lệch giá dịch vụ y tế?',	'Bệnh nhân có giấy chuyển tuyến mới được hướng dẫn ký cam kết đồng ý chi trả khoản chênh lệch giá dịch vụ y tế trong khám, chữa bệnh tại Bệnh viện Tim Hà Nội.',	'{"cam kết chi trả","chênh lệch giá dịch vụ y tế","giấy chuyển tuyến mới"}',	'{"topic": "Bước 3 - Tiếp nhận đăng ký khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	12,	now(),	now()),
('904e18d6-6cb5-413f-a029-a9be49d0350e',	'Bệnh nhân có BHYT cần chuẩn bị gì để thuận tiện cho nhân viên kế toán kiểm tra?',	'Bệnh nhân có BHYT được hướng dẫn chuẩn bị sẵn các giấy tờ cần thiết để thuận tiện cho nhân viên kế toán kiểm tra và tiếp nhận.',	'{"BHYT","chuẩn bị giấy tờ","kế toán kiểm tra"}',	'{"topic": "Bước 3 - Tiếp nhận đăng ký khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	13,	now(),	now()),
('47fa786d-16cc-4e4d-9192-c45550c63ddd',	'Tất cả bệnh nhân đăng ký khám cần xuất trình giấy tờ gì để đối chiếu thông tin?',	'Tất cả bệnh nhân đăng ký khám được đề nghị xuất trình CCCD hoặc giấy tờ tùy thân khác (nếu có) để đối chiếu khi khai thông tin khám bệnh.',	'{"CCCD","giấy tờ tùy thân","đối chiếu thông tin"}',	'{"topic": "Bước 3 - Tiếp nhận đăng ký khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	14,	now(),	now()),
('18ebb909-b3ab-48ba-ac14-62c00e7971eb',	'Nếu bệnh nhân không có CCCD hoặc giấy tờ tùy thân nào khác thì xử lý ra sao?',	'Trường hợp không có CCCD hoặc giấy tờ tùy thân khác, sau khi viết xong thông tin, nhân viên cho bệnh nhân kiểm tra lại thông tin trên bìa hồ sơ khám bệnh.',	'{"không có CCCD","kiểm tra lại thông tin","bìa hồ sơ khám bệnh"}',	'{"topic": "Bước 3 - Tiếp nhận đăng ký khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	15,	now(),	now()),
('33cf4973-af72-4106-b84d-561000182bee',	'Bìa hồ sơ khám bệnh cần ghi đầy đủ những thông tin gì?',	'Bìa hồ sơ khám bệnh ghi đầy đủ các thông tin: họ tên, ngày tháng năm sinh, địa chỉ (tối thiểu từ tuyến xã/phường), số điện thoại.',	'{"bìa hồ sơ khám bệnh","họ tên","ngày sinh","địa chỉ","số điện thoại"}',	'{"topic": "Bước 3 - Tiếp nhận đăng ký khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	16,	now(),	now()),
('f1ecc57c-0a5d-4dcf-ad9c-f2e41c30b64d',	'Làm thế nào để bệnh nhân được phát số vào đúng phòng khám của bác sĩ đã chọn?',	'Tên bác sĩ mà bệnh nhân lựa chọn khám được ghi ngoài sổ khám, để nhân viên phân phòng dựa vào đó phát số vào phòng khám của bác sĩ đó.',	'{"chọn bác sĩ","sổ khám","phân phòng","phát số"}',	'{"topic": "Bước 3 - Tiếp nhận đăng ký khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	17,	now(),	now()),
('37d20ec0-d1cb-430b-a491-bcd055f4bfeb',	'Bệnh nhân thuộc đối tượng ưu tiên được xác định và đánh dấu như thế nào?',	'Bệnh nhân thuộc đối tượng ưu tiên (theo quy định số 154 của BVT ban hành ngày 12/01/2024) sẽ được nhân viên đóng dấu "ưu tiên" lên trên sổ khám.',	'{"đối tượng ưu tiên","quy định số 154","đóng dấu ưu tiên","sổ khám"}',	'{"topic": "Bước 3 - Tiếp nhận đăng ký khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	18,	now(),	now()),
('cd0c4e88-e2ef-49e8-bf44-9ba735e211cc',	'Sau khi đăng ký khám xong, bệnh nhân được hướng dẫn sang những quầy nào để đóng tiền?',	'Bệnh nhân được hướng dẫn sang các quầy kế toán theo đối tượng: quầy dành cho bệnh nhân ưu tiên và đặt lịch khám, quầy dành cho bệnh nhân không ưu tiên và chưa đặt lịch khám.',	'{"quầy kế toán","bệnh nhân ưu tiên","bệnh nhân không ưu tiên"}',	'{"topic": "Bước 3 - Tiếp nhận đăng ký khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	19,	now(),	now()),
('7c47d422-d8d2-4115-b378-913dd5e08330',	'Tại bước thu phí, bệnh nhân có BHYT cần xuất trình lại những giấy tờ gì?',	'Bệnh nhân có BHYT xuất trình giấy chuyển viện, giấy hẹn khám lại, thẻ BHYT hoặc ứng dụng VssID/CCCD gắn chíp có tích hợp thẻ BHYT.',	'{"thu phí","BHYT","giấy chuyển viện","VssID","CCCD gắn chíp"}',	'{"topic": "Bước 4 - Thu phí và tiếp nhận BHYT", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	20,	now(),	now()),
('9939155a-227f-4779-9ec5-529becd4d102',	'Nhân viên kế toán thông báo những khoản phí gì cho bệnh nhân trước khi thu tiền?',	'Nhân viên kế toán thông báo cho bệnh nhân phí khám và phí chênh lệch BHYT (nếu có) trước khi thực hiện thu phí.',	'{"nhân viên kế toán","phí khám","phí chênh lệch BHYT"}',	'{"topic": "Bước 4 - Thu phí và tiếp nhận BHYT", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	21,	now(),	now()),
('d6a640ab-aeda-48fb-b50d-b0480d0aa925',	'Sau khi thu phí, bệnh nhân được hướng dẫn sang bàn nào tiếp theo?',	'Sau khi thu phí, bệnh nhân được hướng dẫn sang bàn đo dấu hiệu sinh tồn, chiều cao, cân nặng.',	'{"sau thu phí","bàn đo dấu hiệu sinh tồn","chiều cao","cân nặng"}',	'{"topic": "Bước 4 - Thu phí và tiếp nhận BHYT", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	22,	now(),	now()),
('6efa80bf-d1ce-4668-a914-4d04f1fda862',	'Tại bàn đo dấu hiệu sinh tồn, bệnh nhân được đo và ghi nhận những gì?',	'Nhân viên thực hiện đo dấu hiệu sinh tồn (DHST), chiều cao, cân nặng và ghi kết quả vào phiếu tiếp nhận bệnh nhân.',	'{"đo dấu hiệu sinh tồn","DHST","chiều cao","cân nặng","phiếu tiếp nhận"}',	'{"topic": "Bước 5 - Đo dấu hiệu sinh tồn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	23,	now(),	now()),
('d91dc947-ed26-4318-a9fe-821c4dcb6d6c',	'Đối tượng bệnh nhân nào được ưu tiên đo dấu hiệu sinh tồn trước?',	'Bệnh nhân thuộc đối tượng ưu tiên theo quy định được ưu tiên thực hiện đo dấu hiệu sinh tồn trước.',	'{"đối tượng ưu tiên","đo DHST trước"}',	'{"topic": "Bước 5 - Đo dấu hiệu sinh tồn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	24,	now(),	now()),
('62b52319-26d9-461b-803b-1a6e2c2cfe48',	'Nếu phát hiện dấu hiệu sinh tồn bất thường thì nhân viên xử lý ra sao?',	'Các trường hợp bất thường được nhân viên báo bác sĩ hoặc chuyển cấp cứu theo hướng dẫn HD.25.01.',	'{"dấu hiệu sinh tồn bất thường","báo bác sĩ","chuyển cấp cứu","HD.25.01"}',	'{"topic": "Bước 5 - Đo dấu hiệu sinh tồn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	25,	now(),	now()),
('0f2063e2-7a16-47df-9dae-1f29f6637773',	'Thứ tự đo huyết áp và đóng tiền có thể thay đổi linh hoạt không?',	'Có. Có thể linh hoạt đo huyết áp trước hoặc đóng tiền trước tùy theo lượng bệnh nhân, nhằm tránh ùn tắc.',	'{"đo huyết áp trước","đóng tiền trước","linh hoạt","tránh ùn tắc"}',	'{"topic": "Bước 5 - Đo dấu hiệu sinh tồn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	26,	now(),	now()),
('ab2b497b-6e79-4c91-815f-71aa03275c01',	'Bệnh nhân chưa được khám được phát số và hướng dẫn như thế nào?',	'Điều dưỡng phát số phân phòng cho bệnh nhân chưa được khám và hướng dẫn bệnh nhân về khu vực chờ khám theo số thứ tự.',	'{"phát số phân phòng","khu vực chờ khám","số thứ tự"}',	'{"topic": "Bước 6 - Hướng dẫn làm CLS và trả kết quả", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	27,	now(),	now()),
('d98b36d7-80ef-49c7-b72d-13a01f511953',	'Bước 1 trong quy trình hướng dẫn bệnh nhân làm cận lâm sàng (CLS) là gì?',	'Bước 1: nhân viên ghi số thứ tự lên các phiếu chỉ định và phiếu thu tiền của bệnh nhân.',	'{"cận lâm sàng","CLS","phiếu chỉ định","phiếu thu tiền","số thứ tự"}',	'{"topic": "Bước 6 - Hướng dẫn làm CLS và trả kết quả", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	28,	now(),	now()),
('0b3a10b9-b803-446d-b888-1625b4a9e373',	'Bước 2 trong quy trình hướng dẫn làm CLS gồm những gì?',	'Bước 2: nhân viên tích các mục bệnh nhân phải làm vào phiếu hướng dẫn để bệnh nhân nắm được quy trình, sau đó trả lại phiếu thu có kẹp phiếu hướng dẫn cho bệnh nhân.',	'{"phiếu hướng dẫn","tích mục cần làm","phiếu thu tiền"}',	'{"topic": "Bước 6 - Hướng dẫn làm CLS và trả kết quả", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	29,	now(),	now()),
('061a45d4-8e5a-4801-9e05-0f7f0190ea54',	'Bệnh nhân có thể phải thực hiện những chỉ định cận lâm sàng nào?',	'Bệnh nhân có thể được đưa đi làm các chỉ định như siêu âm tim, siêu âm bụng mạch, X-quang (XQ), điện tim, ABI... rồi lấy kết quả về.',	'{"siêu âm tim","siêu âm bụng mạch","X-quang","điện tim","ABI"}',	'{"topic": "Bước 6 - Hướng dẫn làm CLS và trả kết quả", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	30,	now(),	now()),
('47f3cb23-2148-4fde-81d1-5930ab99d71b',	'Kết quả cận lâm sàng của bệnh nhân được chuyển về đâu và ai kiểm tra?',	'HDV tại các vị trí được phân công chuyển kết quả CLS của bệnh nhân về bàn trả kết quả để điều dưỡng kiểm tra và ghim vào hồ sơ khám bệnh.',	'{"bàn trả kết quả","điều dưỡng kiểm tra","ghim hồ sơ khám bệnh"}',	'{"topic": "Bước 6 - Hướng dẫn làm CLS và trả kết quả", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	31,	now(),	now()),
('8d5a5e53-eb5f-4903-8904-749768b04d85',	'Trường hợp kết quả CLS bất thường được điều dưỡng xử lý như thế nào?',	'Điều dưỡng chuyển cấp cứu các trường hợp bất thường theo HD.25.01; các trường hợp bất thường khác điều dưỡng xin ý kiến bác sĩ hoặc phát số ưu tiên cho bệnh nhân vào gặp bác sĩ.',	'{"kết quả CLS bất thường","chuyển cấp cứu","HD.25.01","xin ý kiến bác sĩ","số ưu tiên"}',	'{"topic": "Bước 6 - Hướng dẫn làm CLS và trả kết quả", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	32,	now(),	now()),
('f091cd72-4367-471f-aaf1-f4277d509900',	'Khi nào bệnh nhân được phát số vào gặp bác sĩ kết luận?',	'Các trường hợp đã đủ kết quả cận lâm sàng được phát số, trả sổ và hướng dẫn bệnh nhân ngồi chờ vào phòng khám bác sĩ kết luận.',	'{"đủ kết quả","phát số","trả sổ","phòng khám bác sĩ kết luận"}',	'{"topic": "Bước 6 - Hướng dẫn làm CLS và trả kết quả", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	33,	now(),	now()),
('d8929880-5a65-4cf8-b41a-678ca40b02a3',	'Bệnh nhân ngồi chờ khám ở đâu và theo số phòng khám nào?',	'Bệnh nhân được hướng dẫn ngồi ở sảnh chờ theo số phòng khám của bác sĩ đã đăng ký.',	'{"sảnh chờ","số phòng khám","bác sĩ đã đăng ký"}',	'{"topic": "Bước 7 - HDV hành lang", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	34,	now(),	now()),
('16230bc1-bfc0-4e1e-b973-ed13b5773017',	'Bệnh nhân theo dõi lượt gọi vào phòng khám bằng cách nào?',	'Bệnh nhân được hướng dẫn chú ý màn hình điện tử và loa gọi số để vào phòng khám khi được gọi.',	'{"màn hình điện tử","loa gọi số","vào phòng khám"}',	'{"topic": "Bước 7 - HDV hành lang", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	35,	now(),	now()),
('612d91b8-5680-453f-9e89-0f288cebc8b3',	'Số thứ tự 4 chữ số hiển thị trên màn hình điện tử có ý nghĩa gì?',	'Số thứ tự hiển thị gồm 4 chữ số trùng với số khám của bệnh nhân: số đầu là số phòng khám, các số tiếp theo là số thứ tự khám.',	'{"4 chữ số","số phòng khám","số thứ tự khám"}',	'{"topic": "Bước 7 - HDV hành lang", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	36,	now(),	now()),
('1d14b409-ea51-4936-9737-617f9e6312b7',	'HDV hành lang chịu trách nhiệm những công việc gì?',	'HDV hành lang có trách nhiệm quan sát bệnh nhân, báo lại điều dưỡng bàn trả kết quả các thông tin bác sĩ báo lại, các trường hợp hỏng phần mềm, hỏng máy gọi số, bệnh nhân thắc mắc ngoài khả năng giải quyết hoặc các trường hợp bất thường khác.',	'{"HDV hành lang","quan sát bệnh nhân","hỏng phần mềm","hỏng máy gọi số","trường hợp bất thường"}',	'{"topic": "Bước 7 - HDV hành lang", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	37,	now(),	now()),
('8ed8a92a-158d-4360-b9de-8e58024d2c76',	'Bác sĩ gọi bệnh nhân vào phòng khám theo thứ tự nào?',	'Bác sĩ tại các phòng khám gọi lần lượt bệnh nhân theo số khám hiển thị trên phần mềm gọi số.',	'{"gọi số","phần mềm gọi số","thứ tự khám"}',	'{"topic": "Bước 8 - Bác sĩ khám và kê đơn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	38,	now(),	now()),
('f148cbfa-5664-44ae-9e4d-4c5918b7563d',	'Bác sĩ khai thác những thông tin gì khi khám bệnh?',	'Bác sĩ khai thác đủ thông tin bao gồm: dịch tễ học, bệnh sử, triệu chứng cơ năng và thực thể.',	'{"dịch tễ học","bệnh sử","triệu chứng cơ năng","triệu chứng thực thể"}',	'{"topic": "Bước 8 - Bác sĩ khám và kê đơn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	39,	now(),	now()),
('dba3e538-37d7-472c-9bd4-5c5f8e164860',	'Bác sĩ giải thích gì cho bệnh nhân về các xét nghiệm cận lâm sàng?',	'Bác sĩ giải thích về tình trạng bệnh tật, sự cần thiết của các xét nghiệm cận lâm sàng để chẩn đoán bệnh, và tích/in phiếu các xét nghiệm cận lâm sàng nếu có.',	'{"giải thích tình trạng bệnh","xét nghiệm cận lâm sàng","in phiếu xét nghiệm"}',	'{"topic": "Bước 8 - Bác sĩ khám và kê đơn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	40,	now(),	now()),
('bd41aed2-8a6d-48ed-a200-91fa1f4979cc',	'Khi kê đơn thuốc, bác sĩ cần thông báo gì với bệnh nhân?',	'Bác sĩ kê đơn thuốc cần thiết, phù hợp với tình trạng người bệnh theo đúng quy chế kê đơn, đồng thời thông báo/tư vấn với bệnh nhân về loại thuốc và giá thuốc để có sự thống nhất.',	'{"kê đơn thuốc","quy chế kê đơn","giá thuốc","tư vấn bệnh nhân"}',	'{"topic": "Bước 8 - Bác sĩ khám và kê đơn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	41,	now(),	now()),
('ce6e266e-8abe-4472-8d46-568d3e599886',	'Sau khi kê đơn, bác sĩ hướng dẫn bệnh nhân thêm những gì?',	'Bác sĩ hướng dẫn cách sử dụng thuốc, chế độ ăn uống, tập luyện và theo dõi trong quá trình điều trị, đồng thời thông báo lịch khám lại và lưu ý xét nghiệm cho lần khám sau nếu cần.',	'{"hướng dẫn sử dụng thuốc","chế độ ăn uống","tập luyện","lịch khám lại"}',	'{"topic": "Bước 8 - Bác sĩ khám và kê đơn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	42,	now(),	now()),
('ab193e06-dd5a-4db9-b4cf-a3e0fe6b84d8',	'Giấy hẹn khám lại được bác sĩ cấp như thế nào?',	'Bác sĩ cấp giấy hẹn khám lại cho bệnh nhân có ghi rõ ngày khám, giờ khám; với bệnh nhân BHYT, bác sĩ chọn mã hồ sơ trên phần mềm phù hợp với chẩn đoán bệnh và chẩn đoán giấy chuyển (theo HD.25.01).',	'{"giấy hẹn khám lại","ngày khám giờ khám","mã hồ sơ BHYT","HD.25.01"}',	'{"topic": "Bước 8 - Bác sĩ khám và kê đơn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	43,	now(),	now()),
('f9e0f9fd-da57-495e-a39a-e7d49526f157',	'Trường hợp cần chuyển Điều trị ban ngày hoặc Cấp cứu, bác sĩ phải làm gì?',	'Bác sĩ ghi rõ lý do và ký tên bên cạnh các trường hợp cần chuyển Điều trị ban ngày hoặc Cấp cứu; khoa tiếp nhận có trách nhiệm xử trí, giải thích hướng điều trị, kê đơn hoặc cho bệnh nhân vào viện tùy tình trạng.',	'{"chuyển Điều trị ban ngày","Cấp cứu","ghi rõ lý do","ký tên"}',	'{"topic": "Bước 8 - Bác sĩ khám và kê đơn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	44,	now(),	now()),
('66a88f4d-6770-4bc3-9299-5062f50fdd20',	'Nếu bệnh nhân cần nhập viện điều trị, bác sĩ thực hiện thủ tục gì?',	'Bác sĩ giải thích tình trạng và in phiếu vào viện nếu bệnh nhân cần nhập viện điều trị.',	'{"nhập viện điều trị","phiếu vào viện"}',	'{"topic": "Bước 8 - Bác sĩ khám và kê đơn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	45,	now(),	now()),
('2dc58e69-8646-42b7-921c-2265489b1ca1',	'Nếu bệnh nhân cần chuyển tuyến điều trị, bác sĩ thực hiện thủ tục gì?',	'Bác sĩ giải thích tình trạng cho người bệnh, xin ý kiến Ban Giám đốc và in phiếu chuyển viện nếu bệnh nhân cần chuyển tuyến điều trị theo đúng quy định.',	'{"chuyển tuyến điều trị","xin ý kiến Ban Giám đốc","phiếu chuyển viện"}',	'{"topic": "Bước 8 - Bác sĩ khám và kê đơn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	46,	now(),	now()),
('a23e959d-c2ea-43c7-bb93-6375d467b983',	'Với bệnh nhân vào viện hưởng thông tuyến, ai quyết định các xét nghiệm được hưởng bảo hiểm?',	'Với các trường hợp bệnh nhân vào viện hưởng thông tuyến, bác sĩ cho vào viện là người chịu trách nhiệm quyết định các xét nghiệm được hưởng bảo hiểm sau khi bàn hẹn đối tượng.',	'{"thông tuyến","bác sĩ cho vào viện","xét nghiệm hưởng bảo hiểm"}',	'{"topic": "Bước 8 - Bác sĩ khám và kê đơn", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	47,	now(),	now()),
('4be1785d-2106-473b-832d-74eb0bd2cf95',	'Điều dưỡng bàn hẹn khám lại kiểm tra những gì trên đơn thuốc?',	'Điều dưỡng kiểm tra đơn thuốc về việc đủ thuốc và đúng ngày.',	'{"kiểm tra đơn thuốc","đủ thuốc","đúng ngày"}',	'{"topic": "Bước 9 - Điều dưỡng bàn hẹn khám lại", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	48,	now(),	now()),
('c9167bef-b147-466d-9c7d-69f06de6b291',	'Bệnh nhân khám dịch vụ được hướng dẫn tái khám và mua thuốc ở đâu?',	'Đối với bệnh nhân dịch vụ, điều dưỡng hướng dẫn tái khám và đi mua thuốc tại nhà thuốc bệnh viện.',	'{"bệnh nhân dịch vụ","tái khám","nhà thuốc bệnh viện"}',	'{"topic": "Bước 9 - Điều dưỡng bàn hẹn khám lại", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	49,	now(),	now()),
('504c80c9-80c0-4873-809f-1518256771c7',	'Đơn thuốc BHYT cần được đóng dấu gì trước khi qua kế toán duyệt?',	'Đối với đơn thuốc BHYT, nhân viên đóng dấu Kiểm soát BHYT vào cuối đơn thuốc để nhân viên kế toán biết bệnh nhân đã qua bàn hẹn khám lại.',	'{"đơn thuốc BHYT","dấu Kiểm soát BHYT","bàn hẹn khám lại"}',	'{"topic": "Bước 9 - Điều dưỡng bàn hẹn khám lại", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	50,	now(),	now()),
('da00f6d1-5a09-448a-9f52-53295005a421',	'Nếu đơn thuốc BHYT thiếu dấu Kiểm soát BHYT thì xử lý ra sao?',	'Nếu không có dấu Kiểm soát BHYT, nhân viên kế toán sẽ mời bệnh nhân quay lại bàn hẹn khám lại để kiểm tra, đóng dấu trước khi duyệt đơn.',	'{"thiếu dấu","quay lại bàn hẹn khám lại","duyệt đơn"}',	'{"topic": "Bước 9 - Điều dưỡng bàn hẹn khám lại", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	51,	now(),	now()),
('a1633846-7592-4f56-9c30-04e2c4988502',	'Bệnh nhân BHYT chưa có hồ sơ ngoại trú và chưa đủ điều kiện tham gia chương trình cả năm được xử lý thế nào?',	'Nếu bệnh nhân không đủ điều kiện tham gia chương trình BHYT cả năm, điều dưỡng đóng dấu hẹn khám lần 2 và ghi ngày chuyển tuyến lên giấy hẹn khám lại.',	'{"chưa có hồ sơ ngoại trú","không đủ điều kiện","dấu hẹn khám lần 2","ngày chuyển tuyến"}',	'{"topic": "Bước 9 - Điều dưỡng bàn hẹn khám lại", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	52,	now(),	now()),
('4324069f-2c63-4d87-bd47-f4744c3dcd98',	'Bệnh nhân BHYT chưa có hồ sơ ngoại trú nhưng đủ điều kiện tham gia chương trình cả năm được xử lý thế nào?',	'Nếu bệnh nhân đủ điều kiện tham gia chương trình BHYT cả năm, điều dưỡng đóng dấu chương trình phù hợp lên giấy hẹn khám lại và hướng dẫn bệnh nhân không cần xin giấy chuyển.',	'{"đủ điều kiện","dấu chương trình","không cần xin giấy chuyển"}',	'{"topic": "Bước 9 - Điều dưỡng bàn hẹn khám lại", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	53,	now(),	now()),
('27f60976-143c-42a6-8920-00fd5979fee0',	'Bệnh nhân BHYT đã có hồ sơ ngoại trú và đã khám lần 2 thì lần tái khám sau cần gì?',	'Với hồ sơ ngoại trú đã khám lần 2, điều dưỡng hướng dẫn bệnh nhân lần tái khám sau xin giấy chuyển tuyến mới.',	'{"hồ sơ ngoại trú","khám lần 2","giấy chuyển tuyến mới"}',	'{"topic": "Bước 9 - Điều dưỡng bàn hẹn khám lại", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	54,	now(),	now()),
('87fd349c-35e4-4d2f-a278-549585da28de',	'Bệnh nhân BHYT đang theo chương trình quản lý bệnh (hồ sơ ngoại trú) được xử lý thế nào?',	'Với hồ sơ đang theo chương trình, điều dưỡng tiếp tục đóng dấu chương trình đã có vào giấy hẹn khám lại.',	'{"đang theo chương trình","đóng dấu chương trình","giấy hẹn khám lại"}',	'{"topic": "Bước 9 - Điều dưỡng bàn hẹn khám lại", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	55,	now(),	now()),
('29d14035-90f6-487b-8620-d7ba97f90d6b',	'Sau khi qua bàn hẹn khám lại, bệnh nhân BHYT cần làm gì tiếp theo?',	'Bệnh nhân BHYT sau khi qua bàn hẹn khám lại được mời quay lại quầy thu tiền để duyệt bảo hiểm và ký các giấy tờ cần thiết để hoàn thiện thủ tục khám.',	'{"quầy thu tiền","duyệt bảo hiểm","ký giấy tờ","hoàn thiện thủ tục"}',	'{"topic": "Bước 9 - Điều dưỡng bàn hẹn khám lại", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	56,	now(),	now()),
('3e6390bf-2e95-4e0c-84a4-1dc987172f7d',	'Tại bàn hẹn khám lại, những thủ tục đặc biệt nào khác được xử lý?',	'Bàn hẹn khám lại còn xử lý thủ tục nhập viện (theo QT.25.04), thủ tục chuyển tuyến, cấp giấy nghỉ ốm, và liên hệ bác sĩ cho các trường hợp cần xin ý kiến hội chẩn.',	'{"thủ tục nhập viện","QT.25.04","chuyển tuyến","giấy nghỉ ốm","hội chẩn"}',	'{"topic": "Bước 9 - Điều dưỡng bàn hẹn khám lại", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	57,	now(),	now()),
('152d36b3-89bc-4b8d-b407-92849c9613a4',	'Điều dưỡng viên bàn thủ tục hành chính xử lý thủ tục nhập viện như thế nào?',	'Nếu bệnh nhân có chỉ định nhập viện, điều dưỡng viên hướng dẫn và làm các thủ tục nhập viện theo quy trình tiếp nhận bệnh nhân nhập viện điều trị nội trú (QT.25.04).',	'{"chỉ định nhập viện","thủ tục nhập viện","QT.25.04","điều trị nội trú"}',	'{"topic": "Bước 10 - Thủ tục hành chính", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	58,	now(),	now()),
('06876468-8f08-487a-80ad-89e75bf22269',	'Bàn thủ tục hành chính xử lý những thủ tục chuyển tuyến và nghỉ ốm ra sao?',	'Điều dưỡng viên làm thủ tục cho bệnh nhân chuyển tuyến, cấp giấy nghỉ ốm theo yêu cầu của bác sĩ phòng khám.',	'{"chuyển tuyến","cấp giấy nghỉ ốm","yêu cầu bác sĩ"}',	'{"topic": "Bước 10 - Thủ tục hành chính", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	59,	now(),	now()),
('48c4fa5d-bebd-4cb2-b7f7-fcf290bb8450',	'Ngoài nhập viện và chuyển tuyến, bàn thủ tục hành chính còn xử lý gì khác?',	'Điều dưỡng viên còn hướng dẫn và làm các thủ tục hành chính khác theo yêu cầu chuyên môn và phân công nhiệm vụ tại khoa.',	'{"thủ tục hành chính khác","yêu cầu chuyên môn","phân công nhiệm vụ"}',	'{"topic": "Bước 10 - Thủ tục hành chính", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	60,	now(),	now()),
('54deaa29-d891-446d-8085-7b57cd916b7e',	'Kế toán thu những khoản tiền nào đối với đơn thuốc BHYT?',	'Kế toán thu tiền đồng chi trả theo mức hưởng của thẻ BHYT và số tiền chênh lệch với đơn thuốc bảo hiểm (nếu có).',	'{"đồng chi trả","mức hưởng BHYT","chênh lệch đơn thuốc bảo hiểm"}',	'{"topic": "Bước 11 - Kế toán duyệt đơn và thu phí", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	61,	now(),	now()),
('b1288610-6012-467b-baf4-8d3a514f26a2',	'Bệnh nhân mua thuốc dịch vụ thanh toán tiền thuốc ở đâu?',	'Bệnh nhân mua thuốc dịch vụ thanh toán tiền thuốc cho kế toán tại quầy thuốc dịch vụ.',	'{"mua thuốc dịch vụ","thanh toán","quầy thuốc dịch vụ"}',	'{"topic": "Bước 11 - Kế toán duyệt đơn và thu phí", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	62,	now(),	now()),
('ba99bab0-1fc8-4459-9223-ceba80eea774',	'Sau khi thu tiền, nhân viên kế toán xử lý đơn thuốc như thế nào?',	'Nhân viên kế toán đóng dấu đã thu tiền vào đơn thuốc và mời bệnh nhân đi lĩnh thuốc BHYT hoặc mua thuốc dịch vụ.',	'{"đóng dấu đã thu tiền","lĩnh thuốc BHYT","mua thuốc dịch vụ"}',	'{"topic": "Bước 11 - Kế toán duyệt đơn và thu phí", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	63,	now(),	now()),
('97edcf13-db73-44cb-a534-53051f0193da',	'Bệnh nhân cần làm gì trước khi được phát thuốc?',	'Bệnh nhân ký tên vào đơn thuốc trước khi được phát thuốc.',	'{"ký tên đơn thuốc","phát thuốc"}',	'{"topic": "Bước 12 - Lĩnh thuốc / kết thúc khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	64,	now(),	now()),
