('6e5b7eb1-66fd-482f-a1e2-89db43a22385',	'Ai chịu trách nhiệm duyệt xuất thuốc bảo hiểm cho đơn thuốc BHYT?',	'Nhân viên khoa Dược duyệt xuất thuốc bảo hiểm đối với đơn thuốc hưởng BHYT.',	'{"khoa Dược","duyệt xuất thuốc bảo hiểm","đơn thuốc BHYT"}',	'{"topic": "Bước 12 - Lĩnh thuốc / kết thúc khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	66,	now(),	now()),
('b63855ba-9481-4612-8682-687bd442ec62',	'Quy trình khám bệnh kết thúc khi nào?',	'Sau khi phát thuốc theo đơn và đóng dấu đã phát thuốc vào đơn thuốc, bệnh nhân kết thúc quá trình khám và ra về.',	'{"phát thuốc theo đơn","đóng dấu đã phát thuốc","kết thúc khám","ra về"}',	'{"topic": "Bước 12 - Lĩnh thuốc / kết thúc khám", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	67,	now(),	now()),
