('c532c99e-9dcf-4c45-b6f1-989bbade9b36',	'Phiếu hướng dẫn làm xét nghiệm tại Tầng 1 (khu Tự nguyện 1) gồm những mục xét nghiệm nào?',	'Phiếu hướng dẫn làm xét nghiệm Tầng 1 gồm các cột: điện tim, siêu âm tim, siêu âm bụng/tuyến giáp, X-quang, xét nghiệm máu, siêu âm mạch, ABI.',	'{"Phiếu hướng dẫn xét nghiệm","Tầng 1","điện tim","siêu âm tim","X-quang","xét nghiệm máu","ABI"}',	'{"topic": "Phụ lục - Biểu mẫu BM.25.01.01", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	70,	now(),	now()),
('4cbb2ded-5427-408a-8598-eb37c83bf391',	'Tất cả các mục xét nghiệm ở Tầng 1 được thực hiện tại vị trí nào?',	'Vị trí thực hiện tất cả các mục xét nghiệm trong phiếu hướng dẫn Tầng 1 đều là Tầng 1 (T1).',	'{"vị trí thực hiện","Tầng 1","T1"}',	'{"topic": "Phụ lục - Biểu mẫu BM.25.01.01", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	71,	now(),	now()),
('7395a2f6-e802-4aa1-9342-97f8363959f9',	'Bệnh nhân tại Tầng 1 cần lưu ý gì khi làm xét nghiệm và chờ kết quả?',	'Bệnh nhân không tự ý đi làm các chỉ định xét nghiệm; sẽ có nhân viên HDV đưa dẫn đi làm, và không cần chờ lấy kết quả vì kết quả sẽ được chuyển về khu chờ KBTN 1 (Tầng 1).',	'{"không tự ý đi xét nghiệm","HDV đưa dẫn","khu chờ KBTN 1","Tầng 1"}',	'{"topic": "Phụ lục - Biểu mẫu BM.25.01.01", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	72,	now(),	now()),
('5b728ef8-8c5b-479d-81cd-377e109c3cf8',	'Phiếu hướng dẫn làm xét nghiệm tại Tầng 2 gồm những mục xét nghiệm nào?',	'Phiếu hướng dẫn làm xét nghiệm Tầng 2 gồm các cột: điện tim, siêu âm tim, siêu âm bụng - tuyến giáp, X-quang, xét nghiệm máu, siêu âm mạch thận - chi, ABI.',	'{"Phiếu hướng dẫn xét nghiệm","Tầng 2","siêu âm bụng tuyến giáp","siêu âm mạch thận chi","ABI"}',	'{"topic": "Phụ lục - Biểu mẫu BM.25.01.01", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	73,	now(),	now()),
('f0d8a2c6-520e-42a6-9771-d0709ab7cd1e',	'Vị trí thực hiện các xét nghiệm ở Tầng 2 khác gì so với Tầng 1?',	'Ở Tầng 2, các mục điện tim và siêu âm tim thực hiện tại Tầng 2; siêu âm bụng-tuyến giáp thực hiện tại Tầng 1; X-quang tại Tầng 2; xét nghiệm máu tại Tầng 1 — nghĩa là các xét nghiệm được phân bổ ở cả hai tầng tùy loại.',	'{"vị trí thực hiện","Tầng 2","Tầng 1","phân bổ xét nghiệm"}',	'{"topic": "Phụ lục - Biểu mẫu BM.25.01.01", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	74,	now(),	now()),
('5b849223-1b96-488e-bb58-b241c7b1c01f',	'Bệnh nhân tại Tầng 2 chờ làm xét nghiệm ở đâu và cần lưu ý gì?',	'Bệnh nhân tại Tầng 2 ngồi đợi ở sảnh chờ khu ghế sofa, không tự ý đi làm các chỉ định xét nghiệm và không tự ý xuống Tầng 1; nhân viên sẽ gọi tên theo thứ tự để mời đi làm xét nghiệm, và kết quả sẽ được chuyển về khu chờ KBTN 1 (Tầng 2) mà không cần tự chờ lấy.',	'{"sảnh chờ","khu ghế sofa","không tự ý xuống Tầng 1","gọi tên theo thứ tự","khu chờ KBTN 1 Tầng 2"}',	'{"topic": "Phụ lục - Biểu mẫu BM.25.01.01", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	75,	now(),	now()),
('7fdd1eb8-8202-4d1d-ae48-c491ca860cec',	'Vì sao cả ba biểu mẫu (phiếu tiếp nhận ban đầu, phiếu hướng dẫn xét nghiệm Tầng 1 và Tầng 2) đều mang mã BM.25.01.01?',	'Theo phụ lục của quy trình, cả ba biểu mẫu này được liệt kê chung dưới cùng một mã biểu mẫu BM.25.01.01, dùng cho nhóm tài liệu tiếp nhận và hướng dẫn xét nghiệm tại khu Khám bệnh Tự nguyện 1.',	'{"mã biểu mẫu","BM.25.01.01","phiếu tiếp nhận","phiếu hướng dẫn xét nghiệm"}',	'{"topic": "Phụ lục - Biểu mẫu BM.25.01.01", "source_doc": "Quy trình đón tiếp bệnh nhân và KCB ngoại trú - Tự nguyện 1, Cơ sở 1 - BV Tim Hà Nội"}',	'1',	'quy_trinh_don_tiep_bn_tu_nguyen1',	76,	now(),	now());